// T615 DeliveryGateEscrowController — delivery gate + LIFO compensation
const ESCROW_COMPENSATION_CHAIN = ['REFUND_MILESTONE', 'RESTORE_GIG_STATUS'] as const;

async releaseEscrow(milestoneId: string): Promise<DataProcessResult<Record<string, unknown>>> {
  const delivery = (await this.db.searchDocuments('deliveries', { milestoneId })).data?.[0];
  if (!delivery || delivery['status'] !== 'SUBMITTED') {
    return DataProcessResult.failure('DELIVERY_NOT_SUBMITTED', 'Delivery must be SUBMITTED before release');
  }
  // DNA-8: audit BEFORE enqueue
  await this.db.storeDocument('milestones', { milestoneId, status: 'RELEASED' });
  await this.db.storeDocument('escrow-audit', { milestoneId, action: 'ESCROW_RELEASED' });
  await this.queue.enqueue('MilestoneReleased', { milestoneId });
  return DataProcessResult.success({ milestoneId, status: 'RELEASED' });
}

async startLIFOCompensation(milestoneId: string, contractId: string): Promise<DataProcessResult<void>> {
  // LIFO: registered [REFUND_MILESTONE, RESTORE_GIG_STATUS], executed reversed
  const compensationChain = [...ESCROW_COMPENSATION_CHAIN].reverse(); // [RESTORE_GIG_STATUS, REFUND_MILESTONE]
  await this.queue.enqueue('EscrowCompensationStarted', {
    milestoneId, contractId,
    compensationChain, // [RESTORE_GIG_STATUS, REFUND_MILESTONE]
    startedAt: new Date().toISOString()
  });
  return DataProcessResult.success();
}

async getAutoReleaseDays(): Promise<number> {
  // FREEDOM config — NEVER hardcoded
  const config = await this.freedom.getConfig('escrow_auto_release_days');
  return Number(config ?? 7);
}
